```js
const Discord = require('discord.js');
const client = new Discord.Client();
const CommandManager = require('discord.js-commando').CommandManager;
const YamlCommandLoader = require('discord.js-commando').YamlCommandLoader;
const fs = require('fs');
```

4. Define your bot's properties, including the Discord API key and the prefix:
```js
const botProps = {
  token: 'your-bot-token-here',
  prefix: '!'
};
```

5. Create a new instance of the Discord client and define the `on` event handler:
```js
client.on('ready', () => {
  console.log('Ready!');
});
```

6. Create a new instance of the CommandManager class and load the commands from a YAML file:
```js
const commandFiles = fs.readdirSync('./commands').filter(file => file.endsWith('.yml'));
const yamlCommandLoader = new YamlCommandLoader(botProps.prefix);
yamlCommandLoader.loadFolder('./commands');
client.commando = new CommandManager(yamlCommandLoader);
```

7. Define the ban command and add it to the command manager:
```js
const ban = new Discord.CommandBuilder()
  .category('bot')
  .command('ban')
  .do((msg, args) => {
    const userID = args.shift();
    const reason = args.join(' ');
    msg.member.ban(userID).then(() => {
      msg.channel.send(`${userID} was banned with reason: ${reason}`);
    }).catch(err => {
      msg.channel.send(`Could not ban ${userID}: ${err}`);
    });
  })
  .build();

client.commando.addCommand('ban', ban);
```

8. Start the bot and listen for incoming messages:
```js
client.login(botProps.token);
client.on('message', async (msg) => {
  if (msg.content.startsWith(botProps.prefix) && msg.content.split(' ').shift() === 'ban') {
    await client.commands.get('ban').execute(msg, args);
  }
});

msg.channel.send('I am your Discord bot, feel free to try out my commands!');
```

This will create a basic Discord bot that has a single command, ban. When a user sends the `!ban` command followed by a user ID, the bot will ban the user and send a message to the channel with the reason for the ban.

